// S3A-001: 주간 비즈니스 리포트 분석 엔진
// MakeShop 오픈 API 데이터를 분석하여 주간 리포트 생성

const orderResp = $('주문 조회').first().json;
const memberResp = $('회원 통계').first().json;
const cartResp = $('장바구니 조회').first().json;

// --- 데이터 파싱 (MakeShop API: list는 객체, 키=주문번호) ---
function toArray(data) {
  if (Array.isArray(data)) return data;
  if (data && typeof data === 'object') return Object.values(data);
  return [];
}
const rawOrders = toArray(orderResp.list);
const orders = rawOrders.map(function(entry) {
  var o = entry.order || entry;
  o.basket = entry.basket || o.basket || [];
  if (!Array.isArray(o.basket)) o.basket = Object.values(o.basket);
  return o;
});
const members = toArray(memberResp.list);
const carts = toArray(cartResp.list);

const weekStart = $now.minus({days:7}).toFormat('yyyy-MM-dd');
const weekEnd = $now.minus({days:1}).toFormat('yyyy-MM-dd');

// --- 1. 매출 요약 ---
let totalRevenue = 0;
let orderCount = orders.length;
const orderByNum = {}; // 주문번호별 그룹핑
const productSales = {};
const trafficSources = {};
let pcCount = 0;
let mobileCount = 0;
const categoryRevenue = {};
const dailyRevenue = {};
const customerOrders = {}; // userid별 주문 횟수

for (const order of orders) {
  const baskets = order.basket || [];
  const isMobile = (order.pay_path || '').toUpperCase() === 'MOBILE';

  if (isMobile) mobileCount++;
  else pcCount++;

  // 유입 경로
  const rawSource = order.link_url || '';
  let source = '직접방문';
  if (rawSource.includes('naver')) source = '네이버';
  else if (rawSource.includes('google')) source = '구글';
  else if (rawSource.includes('instagram')) source = '인스타그램';
  else if (rawSource.includes('kakao')) source = '카카오';
  else if (rawSource.includes('coupang')) source = '쿠팡';
  else if (rawSource) source = '기타';
  trafficSources[source] = (trafficSources[source] || 0) + 1;

  // 고객 주문 횟수
  const uid = order.userid || order.sender || 'guest';
  customerOrders[uid] = (customerOrders[uid] || 0) + 1;

  // 주문 금액: pay_price 직접 사용 (basket 합산보다 정확)
  var orderTotal = parseInt(order.pay_price || order.total_product_price || order.start_price || 0);
  totalRevenue += orderTotal;

  // basket 상품별 집계
  for (var bi = 0; bi < baskets.length; bi++) {
    var item = baskets[bi];
    var price = parseInt(item.sell_price || item.price || item.product_price || 0);
    var qty = parseInt(item.quantity || item.ea || item.basket_count || 1);
    var itemTotal = price * qty;

    var pName = item.product_name || item.pname || item.branduid || '알수없음';
    if (!productSales[pName]) {
      productSales[pName] = { name: pName, revenue: 0, quantity: 0 };
    }
    productSales[pName].revenue += itemTotal;
    productSales[pName].quantity += qty;

    var cat = item.category_name || item.category || '미분류';
    categoryRevenue[cat] = (categoryRevenue[cat] || 0) + itemTotal;
  }

  // 일별 매출
  const day = (order.order_date || '').slice(0, 10);
  if (day) {
    dailyRevenue[day] = (dailyRevenue[day] || 0) + orderTotal;
  }
}

const avgOrderValue = orderCount > 0 ? Math.round(totalRevenue / orderCount) : 0;

// --- 2. TOP 10 베스트셀러 ---
const top10Products = Object.values(productSales)
  .sort((a, b) => b.revenue - a.revenue)
  .slice(0, 10);

// --- 3. 고객 분석 ---
const uniqueCustomerCount = Object.keys(customerOrders).length;
const repeatBuyers = Object.values(customerOrders).filter(c => c > 1).length;
const repeatRate = uniqueCustomerCount > 0
  ? Math.round((repeatBuyers / uniqueCustomerCount) * 1000) / 10
  : 0;

// 회원 그룹 분석 (회원 API 데이터)
const groupCounts = {};
for (const m of members) {
  const g = m.group_name || '일반';
  groupCounts[g] = (groupCounts[g] || 0) + 1;
}

// 신규 회원 (최근 7일 가입 추정: order_count <= 1)
const newMemberCount = members.filter(m => parseInt(m.order_count || 0) <= 1).length;

// --- 4. 장바구니 이탈 TOP 5 ---
const cartProducts = {};
for (const cart of carts) {
  const pName = cart.product_name || cart.pname || '알수없음';
  cartProducts[pName] = (cartProducts[pName] || 0) + 1;
}
const cartTop5 = Object.entries(cartProducts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([name, count]) => ({ name, count }));

// --- 5. 유입 경로 정렬 ---
const trafficTop = Object.entries(trafficSources)
  .sort((a, b) => b[1] - a[1]);

// --- 6. 카테고리 TOP 5 ---
const categoryTop = Object.entries(categoryRevenue)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5);

// --- 텔레그램 메시지 포맷팅 ---
const fmt = (n) => n.toLocaleString('ko-KR');

let msg = '📊 <b>PRESSCO21 주간 비즈니스 리포트</b>\n';
msg += '━━━━━━━━━━━━━━━━━━\n';
msg += '📅 ' + weekStart + ' ~ ' + weekEnd + '\n\n';

// 매출 요약
msg += '💰 <b>매출 요약</b>\n';
msg += '  총 매출: ' + fmt(totalRevenue) + '원\n';
msg += '  주문 건수: ' + fmt(orderCount) + '건\n';
msg += '  객단가: ' + fmt(avgOrderValue) + '원\n';
msg += '  조회 데이터: 최대 500건 (API 제한)\n\n';

// 기기별
const total = pcCount + mobileCount;
msg += '📱 <b>기기별 비율</b>\n';
if (total > 0) {
  msg += '  PC: ' + pcCount + '건 (' + Math.round(pcCount/total*100) + '%)\n';
  msg += '  모바일: ' + mobileCount + '건 (' + Math.round(mobileCount/total*100) + '%)\n\n';
} else {
  msg += '  데이터 없음\n\n';
}

// TOP 10 베스트셀러
msg += '🏆 <b>TOP 10 베스트셀러</b>\n';
top10Products.forEach((p, i) => {
  const shortName = p.name.length > 20 ? p.name.slice(0, 20) + '..' : p.name;
  msg += '  ' + (i+1) + '. ' + shortName + '\n';
  msg += '     ' + fmt(p.revenue) + '원 / ' + p.quantity + '개\n';
});
msg += '\n';

// 고객 분석
msg += '👥 <b>고객 분석</b>\n';
msg += '  구매 고객: ' + uniqueCustomerCount + '명\n';
msg += '  재구매: ' + repeatBuyers + '명 (' + repeatRate + '%)\n';
if (Object.keys(groupCounts).length > 0) {
  msg += '  회원 그룹: ';
  msg += Object.entries(groupCounts).map(([g,c]) => g + ' ' + c + '명').join(', ') + '\n';
}
msg += '\n';

// 유입 경로
msg += '🔗 <b>유입 경로</b>\n';
trafficTop.forEach(([src, cnt]) => {
  msg += '  ' + src + ': ' + cnt + '건\n';
});
msg += '\n';

// 카테고리 TOP 5
if (categoryTop.length > 0) {
  msg += '📂 <b>카테고리 매출 TOP 5</b>\n';
  categoryTop.forEach(([cat, rev]) => {
    msg += '  ' + cat + ': ' + fmt(rev) + '원\n';
  });
  msg += '\n';
}

// 장바구니 이탈 TOP 5
if (cartTop5.length > 0) {
  msg += '🛒 <b>장바구니 TOP 5 (이탈 분석)</b>\n';
  cartTop5.forEach((item) => {
    const shortName = item.name.length > 25 ? item.name.slice(0, 25) + '..' : item.name;
    msg += '  ' + shortName + ': ' + item.count + '건\n';
  });
  msg += '\n';
}

// 일별 매출
const sortedDays = Object.entries(dailyRevenue).sort();
if (sortedDays.length > 0) {
  msg += '📈 <b>일별 매출</b>\n';
  sortedDays.forEach(([day, rev]) => {
    const shortDay = day.slice(5); // MM-DD
    msg += '  ' + shortDay + ': ' + fmt(rev) + '원\n';
  });
}

msg += '\n🤖 자동 생성 by n8n S3A-001';

// --- NocoDB 스냅샷 데이터 ---
const snapshot = {
  week_start: weekStart,
  week_end: weekEnd,
  total_revenue: totalRevenue,
  order_count: orderCount,
  avg_order_value: avgOrderValue,
  new_customers: newMemberCount,
  repeat_rate: repeatRate,
  unique_customers: uniqueCustomerCount,
  top_products: JSON.stringify(top10Products),
  traffic_sources: JSON.stringify(Object.fromEntries(trafficTop)),
  device_ratio: JSON.stringify({ pc: pcCount, mobile: mobileCount }),
  cart_abandonment: JSON.stringify(cartTop5),
  category_revenue: JSON.stringify(Object.fromEntries(categoryTop)),
  daily_revenue: JSON.stringify(Object.fromEntries(sortedDays)),
  data_note: 'limit=500, partial if >500 orders/week',
  created_at: $now.toISO()
};

return [{ json: { message: msg, snapshot: snapshot } }];
